<?php
/* Plugin Name: Custom User Authentication */

if (!defined('ABSPATH')) {
    exit; // Exit if accessed directly.
}

require_once(ABSPATH . 'wp-includes/wp-auth-check.php');
require_once(ABSPATH . 'wp-includes/pluggable.php');

function custom_user_login($username, $password) {
    global $wpdb;

    // Database table name for users
    $table_name = $wpdb->prefix . "users";

    // Query to get the user by username
    $user = $wpdb->get_row($wpdb->prepare("SELECT * FROM $table_name WHERE user_login = %s", $username));

    if ($user && password_verify($password, $user->user_pass)) {
        wp_set_current_user($user->ID);
        wp_set_auth_cookie($user->ID);
        return true;
    } else {
        return false;
    }
}
add_filter('authenticate', 'custom_user_login', 10, 2);

function custom_user_register($username, $password) {
    // Hash the password using WordPress's built-in password hashing function
    $hashed_password = password_hash($password, PASSWORD_DEFAULT);

    // Insert user into database
    global $wpdb;

    $table_name = $wpdb->prefix . "users";
    $data = array(
        'user_login' => $username,
        'user_pass' => $hashed_password,
        'user_email' => '', // You should replace this with a function to generate a unique email or use an existing one.
        'user_registered' => current_time('mysql'),
        'display_name' => $username
    );

    return $wpdb->insert($table_name, $data);
}
add_filter('user_register', 'custom_user_register', 10, 2);